parameters.jsCode:
const crypto = require("crypto");

return items.map(item => {
  const raw = item.json;

  const workflowName = raw.workflow_name ?? "unknown_workflow";
  const workflowId = raw.workflow_id ?? "unknown_workflow_id";
  const executionId = raw.execution_id ?? "unknown_execution";
  const nodeName = raw.node_name ?? "unknown_node";
  const nodeType = raw.node_type ?? "unknown_node_type";

  const workflowOwnerEmail = raw.workflow_owner_email ?? null;
  const mainDevEmail = raw.main_dev_email ?? null;
  const environment = raw.environment ?? "unknown";

  const statusCode = raw.status_code ? Number(raw.status_code) : null;
  const errorType = raw.error_type ?? "UnknownError";
  const errorMessage = raw.error_message ?? "";
  const errorDescription = raw.error_description ?? "";
  const method = raw.method ?? null;
  const endpoint = raw.endpoint || null;

  const incidentFingerprintBase = [
    workflowId,
    nodeName,
    errorType,
    statusCode,
    method,
    endpoint,
    errorMessage
  ].join("|");

  const incidentKey = crypto
    .createHash("sha256")
    .update(incidentFingerprintBase)
    .digest("hex");

  let failureCategory = "unknown";
  let likelyRetryable = false;

  if ([401, 403].includes(statusCode)) {
    failureCategory = "auth_error";
    likelyRetryable = false;
  } else if (statusCode === 404) {
    failureCategory = "not_found";
    likelyRetryable = false;
  } else if (statusCode === 429) {
    failureCategory = "rate_limit";
    likelyRetryable = true;
  } else if (statusCode >= 500) {
    failureCategory = "server_error";
    likelyRetryable = true;
  } else if (String(errorMessage).toLowerCase().includes("timeout")) {
    failureCategory = "timeout";
    likelyRetryable = true;
  } else if (errorType === "NodeApiError") {
    failureCategory = "api_error";
    likelyRetryable = false;
  }

  return {
    json: {
      raw_incident_id: raw.id,
      incident_key: incidentKey,

      source: raw.source,

      ownership: {
        workflow_owner_email: workflowOwnerEmail,
        main_dev_email: mainDevEmail
      },

      environment,

      workflow: {
        name: workflowName,
        id: workflowId
      },

      execution: {
        id: executionId,
        url: raw.execution_url,
        status: raw.status
      },

      failed_node: {
        name: nodeName,
        type: nodeType
      },

      error: {
        type: errorType,
        message: errorMessage,
        description: errorDescription,
        status_code: statusCode,
        endpoint,
        method
      },

      initial_specs: {
        failure_category: failureCategory,
        likely_retryable: likelyRetryable,
        environment,
        detected_at: new Date().toISOString()
      },

      ai_input: {
        summary_context: `
Workflow "${workflowName}" failed at node "${nodeName}".
Environment: ${environment}
Workflow owner email: ${workflowOwnerEmail}
Main dev email: ${mainDevEmail}
Error type: ${errorType}
Status code: ${statusCode}
Method: ${method}
Endpoint: ${endpoint}
Message: ${errorMessage}
Description: ${errorDescription}
        `.trim()
      }
    }
  };
});

return items.map(item => {
  const incident = item.json;

  const statusCode = incident.error?.status_code ?? null;
  const errorType = incident.error?.type ?? "";
  const message = String(incident.error?.message ?? "").toLowerCase();
  const description = String(incident.error?.description ?? "").toLowerCase();
  const nodeType = incident.failed_node?.type ?? "";
  const nodeName = incident.failed_node?.name ?? "";

  const text = `${message} ${description}`.toLowerCase();

  let classificationStatus = "deterministic_classified";
  let failureCategory = incident.initial_specs?.failure_category ?? "unknown";
  let severity = "low";
  let retryable = false;
  let escalate = false;
  let escalationTarget = "none";
  let action = "Log incident only.";
  let reason = "Failure was classified by deterministic rules.";
  let confidence = 0.75;
  const tags = [];

  if (statusCode === 400) {
    failureCategory = "bad_request";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Check request body, query parameters, and required fields.";
    reason = "400 means the request payload or parameters are invalid.";
    confidence = 0.95;
    tags.push("api", "client_error", "payload_validation");
  } else if (statusCode === 401) {
    failureCategory = "authentication_error";
    severity = "high";
    retryable = false;
    escalate = true;
    escalationTarget = "main_devs";
    action = "Check expired credentials, API keys, OAuth token, or credential sharing.";
    reason = "401 indicates the request is unauthenticated.";
    confidence = 0.98;
    tags.push("api", "auth", "credentials");
  } else if (statusCode === 403) {
    failureCategory = "authorization_error";
    severity = "high";
    retryable = false;
    escalate = true;
    escalationTarget = "main_devs";
    action = "Check scopes, permissions, role access, and API app authorization.";
    reason = "403 means the workflow authenticated but lacks permission.";
    confidence = 0.98;
    tags.push("api", "auth", "permissions");
  } else if (statusCode === 404) {
    failureCategory = "not_found";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Verify endpoint URL, resource ID, route path, and API documentation.";
    reason = "404 usually means the endpoint or requested resource does not exist.";
    confidence = 0.96;
    tags.push("api", "client_error", "not_found");
  } else if (statusCode === 408 || text.includes("timeout") || text.includes("timed out")) {
    failureCategory = "timeout";
    severity = "medium";
    retryable = true;
    escalate = false;
    escalationTarget = "none";
    action = "Retry with backoff. Escalate only if repeated.";
    reason = "Timeouts are often transient and should not escalate on first occurrence.";
    confidence = 0.9;
    tags.push("network", "timeout", "retryable");
  } else if (statusCode === 409) {
    failureCategory = "conflict";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Check duplicate writes, idempotency keys, and race-condition-sensitive operations.";
    reason = "409 usually means conflicting state or duplicate operation.";
    confidence = 0.9;
    tags.push("api", "conflict", "idempotency");
  } else if (statusCode === 422) {
    failureCategory = "validation_error";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Inspect field formats, missing required values, enum constraints, and schema validation.";
    reason = "422 indicates the request was understood but failed validation.";
    confidence = 0.95;
    tags.push("api", "validation", "payload");
  } else if (statusCode === 429) {
    failureCategory = "rate_limit";
    severity = "medium";
    retryable = true;
    escalate = false;
    escalationTarget = "none";
    action = "Retry using exponential backoff and reduce request frequency.";
    reason = "429 indicates rate limiting and is usually retryable.";
    confidence = 0.98;
    tags.push("api", "rate_limit", "retryable");
  } else if (statusCode >= 500 && statusCode <= 599) {
    failureCategory = "external_server_error";
    severity = statusCode === 503 || statusCode === 504 ? "medium" : "high";
    retryable = true;
    escalate = false;
    escalationTarget = "none";
    action = "Retry with backoff. Escalate if the same incident repeats or persists.";
    reason = "5xx errors are usually external service or infrastructure failures.";
    confidence = 0.92;
    tags.push("api", "server_error", "retryable");
  } else if (
    text.includes("invalid json") ||
    text.includes("unexpected token") ||
    text.includes("not valid json") ||
    text.includes("json parse")
  ) {
    failureCategory = "invalid_json";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Check JSON body formatting, expression output, and escaped characters.";
    reason = "JSON parsing failures usually require workflow configuration changes.";
    confidence = 0.93;
    tags.push("payload", "json", "configuration");
  } else if (
    text.includes("cannot read properties") ||
    text.includes("undefined") ||
    text.includes("null") ||
    text.includes("is not iterable")
  ) {
    failureCategory = "data_shape_error";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Check missing fields, null values, input item structure, and previous node output.";
    reason = "The workflow expected a data shape that was not present.";
    confidence = 0.88;
    tags.push("data_shape", "code_node", "mapping");
  } else if (
    text.includes("credential") ||
    text.includes("oauth") ||
    text.includes("token") ||
    text.includes("api key")
  ) {
    failureCategory = "credential_or_oauth_error";
    severity = "high";
    retryable = false;
    escalate = true;
    escalationTarget = "main_devs";
    action = "Check credential validity, token refresh, OAuth scopes, and credential ownership.";
    reason = "Credential and OAuth failures usually need developer or admin intervention.";
    confidence = 0.9;
    tags.push("auth", "oauth", "credentials");
  } else if (
    text.includes("connection refused") ||
    text.includes("econnrefused") ||
    text.includes("enotfound") ||
    text.includes("dns") ||
    text.includes("network")
  ) {
    failureCategory = "network_error";
    severity = "medium";
    retryable = true;
    escalate = false;
    escalationTarget = "none";
    action = "Retry with backoff. Escalate if repeated.";
    reason = "Network failures are commonly transient.";
    confidence = 0.86;
    tags.push("network", "retryable");
  } else if (
    nodeType.includes("code") ||
    nodeName.toLowerCase().includes("code")
  ) {
    failureCategory = "code_node_error";
    severity = "medium";
    retryable = false;
    escalate = true;
    escalationTarget = "workflow_owner";
    action = "Inspect code node logic, input assumptions, and returned item structure.";
    reason = "Code node failures are usually logic or data-shape issues.";
    confidence = 0.82;
    tags.push("code_node", "logic_error");
  } else {
    classificationStatus = "needs_ai_analysis";
    failureCategory = "unknown";
    severity = "unknown";
    retryable = null;
    escalate = null;
    escalationTarget = "ai_required";
    action = "Send incident to AI classifier for deeper analysis.";
    reason = "No deterministic rule confidently matched this failure.";
    confidence = 0.25;
    tags.push("unknown", "needs_ai");
  }

  const environment = incident.initial_specs?.environment ?? incident.environment ?? "test";

  const criticalPatterns = [
    "database",
    "supabase",
    "payment",
    "production",
    "delete",
    "unauthorized",
    "forbidden",
    "security"
  ];

  const hasCriticalPattern = criticalPatterns.some(pattern => text.includes(pattern));

  if (hasCriticalPattern && classificationStatus === "deterministic_classified") {
    severity = severity === "low" ? "high" : severity;
    escalate = true;
    escalationTarget = "main_devs";
    tags.push("critical_pattern");
  }

  if (environment === "test" && severity !== "critical") {
    const allowedMainDevCategories = [
      "authentication_error",
      "authorization_error",
      "credential_or_oauth_error"
    ];

    if (!allowedMainDevCategories.includes(failureCategory) && !hasCriticalPattern) {
      escalationTarget = escalate ? "workflow_owner" : "none";
    }
  }

  const workflowOwnerEmail = incident.ownership?.workflow_owner_email ?? null;
  const mainDevEmail = incident.ownership?.main_dev_email ?? null;

  let notificationTarget = null;

  if (escalationTarget === "main_devs") {
    notificationTarget = mainDevEmail;
  } else if (escalationTarget === "workflow_owner") {
    notificationTarget = workflowOwnerEmail;
  }

  const requiresEmailNotification = Boolean(escalate) && Boolean(notificationTarget);

  let nextStep = "save_classification_only";

  if (classificationStatus === "needs_ai_analysis") {
    nextStep = "send_to_ai_classifier";
  } else if (escalate) {
    nextStep = "save_classification_then_notify";
  }

  let notificationPath = "no_notification";

  if (escalate && escalationTarget === "main_devs") {
    notificationPath = "notify_main_devs";
  } else if (escalate && escalationTarget === "workflow_owner") {
    notificationPath = "notify_workflow_owner";
  }

  return {
    json: {
      ...incident,

      ownership: {
        workflow_owner_email: workflowOwnerEmail,
        main_dev_email: mainDevEmail
      },

      environment,

      deterministic_result: {
        classification_status: classificationStatus,
        failure_category: failureCategory,
        severity,
        retryable,
        escalate,
        escalation_target: escalationTarget,
        recommended_action: action,
        reason,
        confidence,
        tags,
        checked_at: new Date().toISOString(),
        notification_target: notificationTarget,
        requires_email_notification: requiresEmailNotification
      },

      routing: {
        next_step: nextStep,
        notification_path: notificationPath
      }
    }
  };
});

return items.map(item => {
  const data = item.json;

  let baseIncident = data;
  let classification = null;
  let classificationSource = "deterministic";

  if (data.deterministic_result) {
    classification = data.deterministic_result;
    classificationSource = "deterministic";
  }

  else if (data.output || data.text || data.response) {
    classificationSource = "ai";

    const rawAiOutput = data.output ?? data.text ?? data.response;

    try {
      classification =
        typeof rawAiOutput === "string"
          ? JSON.parse(rawAiOutput)
          : rawAiOutput;
    } catch (e) {
      classification = {
        classification_status: "ai_parse_failed",
        failure_category: "unknown",
        severity: "medium",
        retryable: null,
        escalate: true,
        escalation_target: "workflow_owner",
        confidence: 0.2,
        risk_level: "medium",
        human_summary: "AI classifier returned invalid JSON.",
        technical_reasoning: "The AI response could not be parsed as JSON.",
        recommended_action: "Inspect AI Agent output and enforce strict JSON-only response.",
        safe_to_auto_retry: false,
        requires_human_review: true,
        possible_root_causes: ["Invalid AI JSON output"],
        signals_used: ["AI output parse failure"],
        missing_context: [],
        tags: ["ai_parse_failed"]
      };
    }

    baseIncident = data.incident ?? data.original_incident ?? data;
  }

  else {
    classificationSource = "unknown";
    classification = {
      classification_status: "unclassified",
      failure_category: "unknown",
      severity: "medium",
      retryable: null,
      escalate: true,
      escalation_target: "workflow_owner",
      confidence: 0.1,
      risk_level: "medium",
      human_summary: "FlowSentinel could not determine classification source.",
      technical_reasoning: "Input did not contain deterministic_result or AI output.",
      recommended_action: "Inspect workflow routing before the save-classification node.",
      safe_to_auto_retry: false,
      requires_human_review: true,
      possible_root_causes: ["Unexpected workflow data shape"],
      signals_used: ["Missing deterministic_result and AI output"],
      missing_context: ["Original incident object may not have been passed forward"],
      tags: ["routing_error"]
    };
  }

  const workflowOwnerEmail =
    baseIncident.ownership?.workflow_owner_email ??
    baseIncident.workflow_owner_email ??
    null;

  const mainDevEmail =
    baseIncident.ownership?.main_dev_email ??
    baseIncident.main_dev_email ??
    null;

  const environment =
    baseIncident.environment ??
    baseIncident.initial_specs?.environment ??
    classification.environment ??
    "unknown";

  let notificationTarget =
    classification.notification_target ?? null;

  if (!notificationTarget && classification.escalate === true) {
    if (classification.escalation_target === "main_devs") {
      notificationTarget = mainDevEmail;
    } else if (classification.escalation_target === "workflow_owner") {
      notificationTarget = workflowOwnerEmail;
    }
  }

  const requiresEmailNotification =
    Boolean(classification.escalate) && Boolean(notificationTarget);

  return {
    json: {
      raw_incident_id: baseIncident.raw_incident_id ?? null,
      incident_key: baseIncident.incident_key ?? null,

      source: baseIncident.source ?? null,

      workflow_owner_email: workflowOwnerEmail,
      main_dev_email: mainDevEmail,
      environment,

      workflow_name: baseIncident.workflow?.name ?? null,
      workflow_id: baseIncident.workflow?.id ?? null,
      execution_id: baseIncident.execution?.id ?? null,
      execution_url: baseIncident.execution?.url ?? null,

      node_name: baseIncident.failed_node?.name ?? null,
      node_type: baseIncident.failed_node?.type ?? null,

      error_type: baseIncident.error?.type ?? null,
      error_message: baseIncident.error?.message ?? null,
      error_description: baseIncident.error?.description ?? null,
      status_code: baseIncident.error?.status_code ?? null,
      endpoint: baseIncident.error?.endpoint ?? null,
      method: baseIncident.error?.method ?? null,

      classification_source: classificationSource,
      classification_status: classification.classification_status ?? "unknown",
      failure_category: classification.failure_category ?? "unknown",
      severity: classification.severity ?? "medium",
      risk_level: classification.risk_level ?? classification.severity ?? "medium",

      retryable: classification.retryable ?? null,
      safe_to_auto_retry: classification.safe_to_auto_retry ?? classification.retryable ?? false,
      escalate: classification.escalate ?? false,
      escalation_target: classification.escalation_target ?? "none",
      requires_human_review:
        classification.requires_human_review ?? Boolean(classification.escalate),

      notification_target: notificationTarget,
      requires_email_notification: requiresEmailNotification,

      confidence: classification.confidence ?? 0,

      human_summary:
        classification.human_summary ??
        `Workflow ${baseIncident.workflow?.name ?? "unknown"} failed at ${baseIncident.failed_node?.name ?? "unknown node"}.`,

      technical_reasoning:
        classification.technical_reasoning ??
        classification.reason ??
        "Incident classified by FlowSentinel.",

      recommended_action:
        classification.recommended_action ??
        "Inspect the failed execution and workflow configuration.",

      possible_root_causes: classification.possible_root_causes ?? [],
      signals_used: classification.signals_used ?? [],
      missing_context: classification.missing_context ?? [],
      tags: classification.tags ?? [],

      deterministic_result: data.deterministic_result ?? null,
      ai_result: classificationSource === "ai" ? classification : null,
      full_incident: baseIncident,

      created_from_path: classificationSource,
      save_status: "ready_to_save"
    }
  };
});

